# Cache for ZoneInfo objects
_timezone_cache: dict[str, ZoneInfo] = {}
# Cache available_timezones() to avoid filesystem reads on every cache miss
_available_timezones: frozenset[str] = available_timezones()


def timezone(name: str) -> ZoneInfo:
    """Get a timezone by name.

    This function handles:
    - Standard IANA timezone names (e.g., 'Europe/Paris')
    - Deprecated timezone names that were removed in Ubuntu 24.04
    - Caching of ZoneInfo objects for performance

    If the timezone name exists in available_timezones(), it is used directly.
    Otherwise, the alias mapping is checked for deprecated names.

    :param name: Timezone name (e.g., 'Europe/Paris', 'US/Eastern')
    :returns: A ZoneInfo timezone object
    :raises ZoneInfoNotFoundError: If the timezone name is not recognized

    Example::

        >>> tz = timezone('Europe/Paris')
        >>> tz = timezone('US/Eastern')  # Alias for 'America/New_York'
    """
    if name in _timezone_cache:
        return _timezone_cache[name]

    # If the timezone exists directly, use it (don't override available timezones)
    if name in _available_timezones:
        tz = ZoneInfo(name)
        _timezone_cache[name] = tz
        return tz

    # Check if this is a deprecated name that needs mapping
    canonical_name = TIMEZONE_ALIASES.get(name)
    if canonical_name is not None:
        try:
            tz = ZoneInfo(canonical_name)
            _timezone_cache[name] = tz
            return tz
        except KeyError:
            pass  # Fall through to try original name

    # Try the original name as a last resort
    try:
        tz = ZoneInfo(name)
    except KeyError:
        raise KeyError(f"Unknown timezone: {name!r}") from None

    _timezone_cache[name] = tz
    return tz


def localize(dt: datetime, tz: ZoneInfo | dt_timezone) -> datetime:
    """Attach a timezone to a naive datetime.

    Unlike pytz's localize(), this uses the standard library approach
    of replacing the tzinfo. For DST-ambiguous times, the fold attribute
    determines which offset to use (fold=0 for earlier, fold=1 for later).

    :param dt: A naive datetime (tzinfo must be None)
    :param tz: The timezone to attach
    :returns: A timezone-aware datetime
    :raises ValueError: If the datetime already has a timezone

    Example::

        >>> from datetime import datetime
        >>> dt = datetime(2024, 6, 15, 12, 0)
        >>> aware_dt = localize(dt, timezone('Europe/Paris'))
    """
    if dt.tzinfo is not None:
        raise ValueError(f"Cannot localize a datetime that already has tzinfo: {dt}")
    return dt.replace(tzinfo=tz)


def all_timezones() -> frozenset[str]:
    """Return all available timezone names.

    :returns: A frozenset of timezone names available on this system
    """
    return _available_timezones


# Cached country -> timezones mapping
_country_timezones: dict[str, list[str]] | None = None


def country_timezones() -> dict[str, list[str]]:
    """Return a mapping of country codes to their timezone names.

    Uses babel's zone_territories data to build the mapping.
    This replaces pytz.country_timezones.

    :returns: A dict mapping ISO 3166 country codes to lists of timezone names

    Example::

        >>> country_timezones()['US']
        ['America/Adak', 'America/Anchorage', ...]
        >>> country_timezones()['JP']
        ['Asia/Tokyo']
    """
    global _country_timezones
    if _country_timezones is None:
        from babel.core import get_global

        zone_territories = get_global("zone_territories")
        _country_timezones = {}
        for tz_name, country_code in zone_territories.items():
            if country_code not in _country_timezones:
                _country_timezones[country_code] = []
            _country_timezones[country_code].append(tz_name)
    return _country_timezones
